query:
{
  pods(
    where: {
      managerName: { eq: "" }
      OR: [
        {
          isAutomountServiceAccountTokenSet: { eq: true }
          automountServiceAccountToken: { eq: true }
        }
        {
          isAutomountServiceAccountTokenSet: { eq: false }
          serviceAccount: {
            isAutomountServiceAccountTokenSet: { eq: true }
            automountServiceAccountToken: { eq: true }
          }
        }
        {
          isAutomountServiceAccountTokenSet: { eq: false }
          serviceAccount: { isAutomountServiceAccountTokenSet: { eq: false } }
        }
      ]
    }
  ) {
    ...AssetFragment
  }
}
